### 4. Add `BindingVmServiceFake` fixture-serving unit tests

File: `packages/exploration_agent/test/_support/binding_vm_service_fake_test.dart`

Add a new `group('observation fixture serving', ...)` with two tests. Use a minimal `ExplorationBinding` (no plugins beyond core, mirroring the existing test setup in this file).

```dart
group('observation fixture serving', () {
  test('returns fixture body wrapped in Observation envelope when '
      'fixture is supplied', () async {
    final binding = ExplorationBinding.ensureInitialized(
      plugins: const <ExplorationPlugin>[],
      installCorePlugin: false,
    )!;
    await Future<void>.delayed(Duration.zero);

    final Map<String, dynamic> body = <String, dynamic>{
      'core': <String, dynamic>{
        'routeStack': <String>['login'],
        'nodes': <String, dynamic>{
          'n1': <String, dynamic>{
            'id': 'n1',
            'label': 'Email',
            'rect': <double>[0, 0, 100, 40],
          },
        },
      },
      'plugins': <String, dynamic>{},
      'stability': <String, dynamic>{'policy': 'action_relative'},
    };
    final fixture = ObservationFixture._forTest('<test>', body);

    final fake = BindingVmServiceFake(binding, observationFixture: fixture);
    final Response r = await fake.callServiceExtension(
      'ext.flutter.exploration.core.get_stable_observation',
      args: <String, dynamic>{'policy': 'action_relative'},
    );
    expect(r.json, isNotNull);
    expect(r.json!['type'], 'Observation');
    expect(r.json!['value'], body);
  });

  test('without a fixture, get_stable_observation still falls through '
      'to the binding (existing behavior preserved)', () async {
    // The existing routing regression test in this file already proves
    // the fall-through path. Re-assert here by constructing the fake
    // with no fixture and confirming the binding's real (empty-tree)
    // observation is returned: r.json['value']['core']['nodes'] is the
    // empty map.
    final binding = ExplorationBinding.ensureInitialized(
      plugins: const <ExplorationPlugin>[],
    )!;
    await Future<void>.delayed(Duration.zero);
    binding.debugSetPolicyLoopSeamsForTesting(
      waitForFrame: () async {},
      nowMs: () => 0,
    );

    final fake = BindingVmServiceFake(binding); // no fixture
    final Response r = await fake.callServiceExtension(
      'ext.flutter.exploration.core.get_stable_observation',
      args: <String, dynamic>{'policy': 'action_relative'},
    );
    final Map<String, dynamic> envelope = r.json!;
    expect(envelope['type'], 'Observation');
    final Map<String, dynamic> bundle =
        (envelope['value'] as Map).cast<String, dynamic>();
    expect(bundle.containsKey('core'), isTrue);
    // Real binding's empty-tree response has zero nodes.
    final Map<String, dynamic> core =
        (bundle['core'] as Map).cast<String, dynamic>();
    final Object? nodes = core['nodes'];
    final int nodeCount =
        nodes is Map ? nodes.length : (nodes is List ? nodes.length : 0);
    expect(nodeCount, 0);
  });
});
```

