   Future<void> writeFooter({
     required String outcome,
     String? exception,
     String? recoveryError,
   }) async {
     // ... existing body ...
     await _sink.writeLine(jsonEncode(<String, Object?>{
       'type': 'dogfood_footer',
       'outcome': outcome,
       if (exception != null) 'exception': exception,
       if (recoveryError != null) 'recovery_error': recoveryError,
