   class PluginFailureTracker {
     static const int autoDisableThreshold = 3;
     final Map<String, int> _c = {};
     /// Returns true iff this failure brings the count to [autoDisableThreshold].
     bool recordFailure(String ns) {
       final n = (_c[ns] ?? 0) + 1; _c[ns] = n; return n >= autoDisableThreshold;
     }
     void recordSuccess(String ns) => _c[ns] = 0;
     int failuresFor(String ns) => _c[ns] ?? 0;
