   ```dart
   import 'dart:async';
   import 'dart:convert';
   import 'package:http/http.dart' as http;
   import '../action_schema.dart';
   import '../model_provider.dart';
   import '../types.dart';
   import '../frontier/tool_helpers.dart';
   import 'swift_infer_config.dart';

   class SwiftInferModelProvider implements ModelProvider {
     final SwiftInferConfig config;
     final http.Client _client;
     final StreamController<ThinkingDelta> _thinking = StreamController.broadcast();

     SwiftInferModelProvider({required this.config, http.Client? client})
         : _client = client ?? http.Client();

     @override
     ModelCapabilities get capabilities => ModelCapabilities(
       vision: config.enableVision,
       preserveThinking: config.preserveThinking,
       maxContext: 128000,
       supportsToolUse: true,
     );

     @override
     Stream<ThinkingDelta> thinking() => _thinking.stream;

     Map<String, dynamic> _buildBody(PromptPayload prompt, {required bool stream}) {
       final messages = [{
         'role': 'user',
         'content': config.enableVision
             ? prompt.userMessages
             : prompt.userMessages.where((b) => b['type'] != 'image').toList(),
       }];
       return {
         'model': config.model,
         'max_tokens': config.maxTokens,
         'temperature': config.temperature,
         'top_p': config.topP,
         'top_k': config.topK,
         'presence_penalty': config.presencePenalty,
         'repetition_penalty': config.repetitionPenalty,
         'preserve_thinking': config.preserveThinking,
         'stream': stream,
         'system': prompt.systemMessage,
         'tools': prompt.tools.map((t) => {
           'name': encodeToolName(t.name),
           'description': t.description,
           'input_schema': t.inputSchema,
         }).toList(),
         'messages': messages,
       };
     }

     Map<String, String> _headers() {
       final h = {
         'content-type': 'application/json',
         'anthropic-version': '2023-06-01',
       };
       if (config.apiKey != null) h['x-api-key'] = config.apiKey!;
       return h;
     }

     @override
     Future<ModelDecision> decide(PromptPayload prompt, ActionSchema schema) async {
       final endpoint = config.baseUrl.resolve('/v1/messages');
       final req = http.Request('POST', endpoint)
         ..headers.addAll(_headers())
         ..body = jsonEncode(_buildBody(prompt, stream: true));
       final streamed = await _client.send(req);
       final raw = StringBuffer();
       Map<String, dynamic>? toolUse;
       bool inThink = false;
       await for (final line in streamed.stream
           .transform(utf8.decoder)
           .transform(const LineSplitter())) {
         if (!line.startsWith('data: ')) continue;
         final payload = line.substring(6).trim();
         if (payload.isEmpty || payload == '[DONE]') continue;
         final evt = jsonDecode(payload) as Map<String, dynamic>;
         final type = evt['type'] as String?;
         if (type == 'content_block_start') {
           final block = evt['content_block'] as Map<String, dynamic>;
           if (block['type'] == 'tool_use') toolUse = {...block, 'input_json': StringBuffer()};
         } else if (type == 'content_block_delta') {
           final delta = evt['delta'] as Map<String, dynamic>;
           if (delta['type'] == 'text_delta') {
             final text = delta['text'] as String;
             raw.write(text);
             _emitThinking(text, inThink: inThink, onBoundary: (newState) => inThink = newState);
           } else if (delta['type'] == 'input_json_delta' && toolUse != null) {
             (toolUse['input_json'] as StringBuffer).write(delta['partial_json']);
           }
         }
       }
       if (toolUse == null) {
         throw SchemaRejection(
           validationError: 'no tool_use block in response',
           rawOutput: raw.toString(),
         );
       }
       final wireName = toolUse['name'] as String;
       final inputJson = (toolUse['input_json'] as StringBuffer).toString();
       final args = inputJson.isEmpty
           ? <String, dynamic>{}
           : (jsonDecode(inputJson) as Map).cast<String, dynamic>();
       final dottedName = lookupTool(prompt.tools, wireName)?.name ?? wireName;
       final envelope = jsonEncode({'action': {'tool': dottedName, 'args': args}});
       final validated = schema.validate(envelope);
       final action = validated['action'] as Map<String, dynamic>;
       return ModelDecision(
         action: (
           tool: action['tool'] as String,
           args: (action['args'] as Map).cast<String, dynamic>(),
         ),
       );
     }

     void _emitThinking(String text, {required bool inThink, required void Function(bool) onBoundary}) {
       var i = 0;
       var state = inThink;
       while (i < text.length) {
         if (!state) {
           final open = text.indexOf('<think>', i);
           if (open < 0) break;
           i = open + '<think>'.length;
           state = true;
         } else {
           final close = text.indexOf('</think>', i);
           if (close < 0) {
             _thinking.add(ThinkingDelta(text: text.substring(i), isFinal: false));
             i = text.length;
           } else {
             if (close > i) _thinking.add(ThinkingDelta(text: text.substring(i, close), isFinal: false));
             _thinking.add(const ThinkingDelta(text: '', isFinal: true));
             i = close + '</think>'.length;
             state = false;
           }
         }
       }
       onBoundary(state);
     }
   }
   ```

