   Add `json_schema: ^5.1.7` to `packages/exploration_agent/pubspec.yaml` deps.

   ```dart
   import 'dart:convert';
   import 'package:json_schema/json_schema.dart';
   import 'types.dart';

   class ActionSchema {
     final Map<String, dynamic> jsonSchema;
     final JsonSchema _validator;
     ActionSchema._(this.jsonSchema, this._validator);

     /// Per-turn schema composer. MUST be called every turn (PRD §16.2).
     factory ActionSchema.fromToolList(List<ToolDescriptor> tools) {
       Map<String, dynamic> variant(ToolDescriptor t) => {
         'type': 'object',
         'required': ['tool', 'args'],
         'properties': {
           'tool': {'type': 'string', 'const': t.name},
           'args': t.inputSchema,
         },
         'additionalProperties': false,
       };
       final root = <String, dynamic>{
         r'$schema': 'http://json-schema.org/draft-07/schema#',
         'type': 'object',
         'required': ['action'],
         'properties': {
           'action': {'oneOf': tools.map(variant).toList()},
           'summary_update': {'type': ['string', 'null']},
           'rationale': {'type': ['string', 'null']},
           'wait_strategy': {'type': ['string', 'null']},
         },
         'additionalProperties': false,
       };
       return ActionSchema._(root, JsonSchema.create(root, schemaVersion: SchemaVersion.draft7));
     }

     /// Throws [SchemaRejection] on failure; returns decoded map on success.
     Map<String, dynamic> validate(String rawOutput) {
       Map<String, dynamic> decoded;
       try { decoded = jsonDecode(rawOutput) as Map<String, dynamic>; }
       catch (e) {
         throw SchemaRejection(validationError: 'output is not valid JSON: $e', rawOutput: rawOutput);
       }
       final r = _validator.validate(decoded);
       if (!r.isValid) {
         throw SchemaRejection(
           validationError: r.errors.map((e) => e.toString()).join('; '),
           rawOutput: rawOutput);
       }
       return decoded;
     }
   }
   ```

