   ```dart
   Future<Map<String,dynamic>> getStableObservation(ObservationRequest req) async {
     assert(kDebugMode);
     final loop = PolicyLoop(frameworkBusySnapshot, pluginRegistry.plugins,
         _semanticsTreeHash, _routeStackHash);
     final tick = await loop.run(req);
     final stability = StabilityMetadata(policy: req.policy, terminatedBy: tick.reason,
       durationMs: tick.durationMs, frameworkBusy: frameworkBusySnapshot().toJson(),
       pluginsBusy: tick.pluginsBusy);
     final core = await buildCoreFragment(
       captureSemantics: semanticsCapture.captureJson,
       errorsSince: errorRingBuffer.since,
       stability: stability,
       includeScreenshot: req.includeScreenshot,
       captureScreenshot: req.includeScreenshot ? screenshotCapture.captureBase64Png : null,
       errorCursor: req.errorCursor);
     final coreEnc = encodeWithBudget(core, 4096);
     if (coreEnc.truncated) developer.log('core fragment truncated', name: 'exploration');
     final budgets = distributePluginBudgets(req.pluginBudgets, pluginRegistry.namespaces);
     final pluginsOut = <String,dynamic>{};
     for (final p in pluginRegistry.plugins) {
       try {
         final frag = await p.observe(pluginRegistry.contextFor(p));
         final enc = encodeWithBudget(frag, budgets[p.namespace]!);
         if (enc.truncated) developer.log('plugin ${p.namespace} fragment truncated', name: 'exploration');
         pluginsOut[p.namespace] = jsonDecode(enc.json);
       } catch (e, st) { pluginRegistry.recordStrike(p, 'observe', e, st); }
     }
     return { ...jsonDecode(coreEnc.json) as Map<String,dynamic>, 'plugins': pluginsOut };
   }
   // in initServiceExtensions():
   if (kDebugMode) registerServiceExtension(name: 'core.get_stable_observation',
     callback: (params) async => {'type':'Observation',
       'value': await getStableObservation(ObservationRequest.fromJson(params))});
