```dart
/// Value types for the dogfood harness. Library-internal: not exported
/// from `lib/exploration_agent.dart` per the harness's "private until
/// the pattern proves itself" policy.
library;

import 'package:meta/meta.dart';

/// Terminal outcome of one `AgentDogfoodHarness.run()` call. Maps 1:1
/// to the CLI's exit-code table:
///   completedWithToolCall  -> 0
///   completedNoToolCall    -> 0
///   typedException         -> 1
///   budgetExceeded         -> 2
/// (Configuration errors exit 3 from the CLI shim; they are caught
///  before the harness runs and never produce a [DogfoodRunResult].)
enum DogfoodOutcome {
  completedWithToolCall,
  completedNoToolCall,
  typedException,
  budgetExceeded,
}

@immutable
class DogfoodRunResult {
  const DogfoodRunResult({
    required this.outcome,
    required this.tracePath,
    required this.turnCount,
    required this.toolCallCount,
    this.exception,
  });
  final DogfoodOutcome outcome;
  final String tracePath;
  final int turnCount;
  final int toolCallCount;
  final Object? exception;
}

/// Thrown synchronously from `AgentDogfoodHarness.run()` when the
/// caller supplied invalid configuration (unreadable fixture file,
/// negative budget, etc.). The CLI catches this and exits 3.
class DogfoodConfigError extends ArgumentError {
  DogfoodConfigError(String message) : super(message);
}
```

