### 4. Trace writer adapter — `packages/exploration_agent/lib/src/dogfood/trace_writer.dart`

Thin wrapper that turns per-turn dogfood events into JSONL lines on a
caller-supplied `TrajectorySink`. Reuses the existing
`TrajectorySink` interface (no new sink type needed).

```dart
library;

import 'dart:convert';

import '../provider/types.dart' show ToolDescriptor;
import '../trajectory/sink.dart';

class DogfoodTraceWriter {
  DogfoodTraceWriter(this._sink, this.path);
  final TrajectorySink _sink;
  final String path;
  bool _headerWritten = false;

  Future<void> writeHeader({
    required String goal,
    required String model,
    required List<ToolDescriptor> tools,
  }) async {
    _headerWritten = true;
    await _sink.writeLine(jsonEncode(<String, Object?>{
      'type': 'dogfood_header',
      'goal': goal,
      'model': model,
      'tools': <Map<String, Object?>>[
        for (final ToolDescriptor t in tools)
          <String, Object?>{'name': t.name, 'description': t.description},
      ],
      'started_at': DateTime.now().toUtc().toIso8601String(),
    }));
    await _sink.flush();
  }

  Future<void> writeTurn({
    required int index,
    required String prompt,
    required Map<String, dynamic>? decision,
    required Map<String, dynamic>? actResult,
    required int elapsedMs,
    String? error,
  }) async {
    assert(_headerWritten);
    await _sink.writeLine(jsonEncode(<String, Object?>{
      'type': 'dogfood_turn',
      'index': index,
      'prompt': prompt,
      'decision': decision,
      'act_result': actResult,
      'elapsed_ms': elapsedMs,
      if (error != null) 'error': error,
    }));
    await _sink.flush();
  }

  Future<void> writeFooter({
    required String outcome,
    String? exception,
  }) async {
    await _sink.writeLine(jsonEncode(<String, Object?>{
      'type': 'dogfood_footer',
      'outcome': outcome,
      if (exception != null) 'exception': exception,
      'ended_at': DateTime.now().toUtc().toIso8601String(),
    }));
    await _sink.flush();
    await _sink.close();
  }
}
```

