### 5. Harness core — `packages/exploration_agent/lib/src/dogfood/agent_dogfood_harness.dart`

The library entrypoint. Takes a `VmService` (caller-built — the test
hands it the binding fake, the CLI also hands it the binding fake but
wires a different log sink), a `SwiftInferConfig`, the goal, the tool
descriptors, the fixture, budgets, and a `TrajectorySink`. Drives one
session via `ExplorationSession.fromVmService` + `session.run()`.

```dart
library;

import 'dart:async';

import 'package:vm_service/vm_service.dart' show VmService;

import '../../exploration_agent.dart'
    show
        ActionRing,
        DefaultLoopHost,
        ExplorationConfig,
        ExplorationSession,
        HarnessError,
        RunningSummary,
        SchemaRejection,
        SessionOutcome,
        SessionTermination,
        StabilityPolicy,
        ToolDescriptor,
        TrajectorySink,
        TrajectoryWriter,
        TurnTimeoutError,
        WhitespaceTokenCounter;
import '../provider/swift_infer/swift_infer_config.dart';
import '../provider/swift_infer/swift_infer_provider.dart';
import 'observation_fixture.dart';
import 'trace_writer.dart';
import 'types.dart';

class AgentDogfoodHarness {
  AgentDogfoodHarness({
    required this.vm,
    required this.isolateId,
    required this.swiftInferConfig,
    required this.goal,
    required this.tools,
    required this.fixture,
    required this.maxTurns,
    required this.maxTurnBudgetMs,
    required this.traceSink,
    required this.tracePath,
    this.verbose = false,
    void Function(String)? log,
  })  : _log = log ?? ((_) {}),
        assert(maxTurns > 0),
        assert(maxTurnBudgetMs > 0);

  final VmService vm;
  final String isolateId;
  final SwiftInferConfig swiftInferConfig;
  final String goal;
  final List<ToolDescriptor> tools;
  final ObservationFixture fixture;
  final int maxTurns;
  final int maxTurnBudgetMs;
  final TrajectorySink traceSink;
  final String tracePath;
  final bool verbose;
  final void Function(String) _log;

  Future<DogfoodRunResult> run() async {
    final DogfoodTraceWriter trace = DogfoodTraceWriter(traceSink, tracePath);
    await trace.writeHeader(
      goal: goal,
      model: swiftInferConfig.model,
      tools: tools,
    );
    if (verbose) {
      _log('[dogfood] start goal="$goal" tools=${tools.map((t) => t.name).toList()}');
    }
    final SwiftInferModelProvider provider =
        SwiftInferModelProvider(config: swiftInferConfig);
    final ExplorationSession session =
        ExplorationSession.fromVmService(vm, isolateId);
    try {
      await session.start(goal, const ExplorationConfig());
      final DefaultLoopHost host = DefaultLoopHost.fromSession(
        session: session,
        coreTools: tools,
        pluginTools: const <String, List<ToolDescriptor>>{},
        goal: goal,
        agentsMd: '',
        policy: StabilityPolicy.actionRelative,
      );
      // The loop driver's own per-turn budget is 30s; we shrink it via
      // a Timer-driven cancellation envelope so smaller --max-turn-budget-ms
      // values are honoured by the harness even though the driver itself
      // is hard-coded to 30s in v1.
      final int toolCalls = <int>[0].first; // initialized below by the host
      // (counter is wired in step 6 via a wrapping LoopHost adapter.)
      final TrajectoryWriter writer = TrajectoryWriter(traceSink);
      final Duration totalBudget = Duration(
        milliseconds: maxTurns * maxTurnBudgetMs + 5000,
      );
      final SessionTermination term = await session
          .run(host: host, provider: provider, writer: writer)
          .timeout(totalBudget, onTimeout: () {
        throw TurnTimeoutError(-1);
      });
      final DogfoodOutcome outcome = _classify(term, toolCalls);
      await trace.writeFooter(outcome: outcome.name);
      return DogfoodRunResult(
        outcome: outcome,
        tracePath: tracePath,
        turnCount: maxTurns,
        toolCallCount: toolCalls,
      );
    } on TurnTimeoutError catch (e) {
      await trace.writeFooter(
        outcome: DogfoodOutcome.budgetExceeded.name,
        exception: e.toString(),
      );
      return DogfoodRunResult(
        outcome: DogfoodOutcome.budgetExceeded,
        tracePath: tracePath,
        turnCount: maxTurns,
        toolCallCount: 0,
        exception: e,
      );
    } on SchemaRejection catch (e) {
      await trace.writeFooter(
        outcome: DogfoodOutcome.typedException.name,
        exception: e.toString(),
      );
      return DogfoodRunResult(
        outcome: DogfoodOutcome.typedException,
        tracePath: tracePath,
        turnCount: 0,
        toolCallCount: 0,
        exception: e,
      );
    } finally {
      await session.end();
    }
  }

  DogfoodOutcome _classify(SessionTermination t, int toolCalls) {
    if (t.harnessError == HarnessError.connectionLost) {
      return DogfoodOutcome.typedException;
    }
    return toolCalls > 0
        ? DogfoodOutcome.completedWithToolCall
        : DogfoodOutcome.completedNoToolCall;
  }
}
```

Note: this draft references a tool-call counter wired through a
host-wrapping adapter; step 6 introduces that adapter explicitly so
the counter is correct rather than the placeholder `0` shown above.

