### 8. CLI shim — `packages/exploration_agent/tool/agent_dogfood.dart`

Argparse + binding boot + harness call. Builds a real
`ExplorationBinding` (with whatever plugin set the `--tools` flag
implies — for v1, supply a tiny in-tool stand-in plugin matching the
namespaces the user requested), wraps it in `BindingVmServiceFake`,
constructs the harness, runs it, exits per the table.

```dart
// Dogfood CLI for the exploration agent. See bead lenny-cx6.43.
//
// dart run packages/exploration_agent/tool/agent_dogfood.dart --help
import 'dart:io';

import 'package:args/args.dart';
import 'package:exploration_agent/src/dogfood/agent_dogfood_harness.dart';
import 'package:exploration_agent/src/dogfood/observation_fixture.dart';
import 'package:exploration_agent/src/dogfood/types.dart';
import 'package:exploration_agent/src/provider/swift_infer/swift_infer_config.dart';
import 'package:exploration_agent/src/provider/types.dart' show ToolDescriptor;
import 'package:exploration_cli/exploration_cli.dart' show FileTrajectorySink;
import 'package:exploration_flutter/contract.dart';
import 'package:exploration_flutter/exploration_flutter.dart';

import '../test/_support/binding_vm_service_fake.dart';

ArgParser _buildParser() => ArgParser()
  ..addOption('goal', mandatory: true)
  ..addOption('tools', mandatory: true,
      help: 'comma-separated qualified names, e.g. router.navigate,core.tap')
  ..addOption('endpoint',
      help: 'falls back to SWIFT_INFER_ENDPOINT')
  ..addOption('token',
      help: 'falls back to SWIFT_INFER_AGENT_TOKEN')
  ..addOption('model', defaultsTo: 'qwen3.6-27b')
  ..addOption('observation-fixture')
  ..addOption('max-turns', defaultsTo: '3')
  ..addOption('max-turn-budget-ms', defaultsTo: '30000')
  ..addFlag('verbose', defaultsTo: true)
  ..addOption('trace-out')
  ..addFlag('help', abbr: 'h', negatable: false);

Future<int> main(List<String> argv) async {
  final ArgParser parser = _buildParser();
  final ArgResults r;
  try {
    r = parser.parse(argv);
  } on FormatException catch (e) {
    stderr.writeln('argument error: ${e.message}');
    stderr.writeln(parser.usage);
    return 3;
  }
  if (r['help'] as bool) {
    stdout.writeln('agent_dogfood — drive the agent against swift-infer');
    stdout.writeln(parser.usage);
    return 0;
  }
  // Resolve endpoint/token with env fallback; error 3 if missing.
  final String? endpoint =
      (r['endpoint'] as String?) ?? Platform.environment['SWIFT_INFER_ENDPOINT'];
  final String? token =
      (r['token'] as String?) ?? Platform.environment['SWIFT_INFER_AGENT_TOKEN'];
  if (endpoint == null || endpoint.isEmpty) {
    stderr.writeln('missing --endpoint or SWIFT_INFER_ENDPOINT');
    return 3;
  }
  if (token == null || token.isEmpty) {
    stderr.writeln('missing --token or SWIFT_INFER_AGENT_TOKEN');
    return 3;
  }
  // Parse --tools, validate each contains a '.'.
  final List<String> toolNames =
      (r['tools'] as String).split(',').map((s) => s.trim()).toList();
  for (final String t in toolNames) {
    if (!t.contains('.')) {
      stderr.writeln('invalid tool name (missing namespace): $t');
      return 3;
    }
  }
  // Resolve fixture (or empty).
  ObservationFixture fixture;
  final String? fixturePath = r['observation-fixture'] as String?;
  try {
    fixture = fixturePath == null
        ? ObservationFixture.empty()
        : await ObservationFixture.loadFromFile(fixturePath);
  } on DogfoodConfigError catch (e) {
    stderr.writeln(e.message);
    return 3;
  }
  // Boot binding with a stand-in plugin per requested namespace.
  final Set<String> namespaces =
      toolNames.map((t) => t.split('.').first).toSet()..remove('core');
  final ExplorationBinding binding = ExplorationBinding.ensureInitialized(
    plugins: <ExplorationPlugin>[
      for (final String ns in namespaces) _StandInPlugin(ns, toolNames),
    ],
  )!;
  await Future<void>.delayed(Duration.zero);
  int now = 0;
  binding.debugSetPolicyLoopSeamsForTesting(
    waitForFrame: () async { now += 16; },
    nowMs: () => now,
  );
  final BindingVmServiceFake fake = BindingVmServiceFake(binding);
  final String tracePath = (r['trace-out'] as String?) ??
      '/tmp/agent-dogfood-${DateTime.now().millisecondsSinceEpoch ~/ 1000}.jsonl';
  final FileTrajectorySink sink = await FileTrajectorySink.open(tracePath);
  final AgentDogfoodHarness harness = AgentDogfoodHarness(
    vm: fake,
    isolateId: 'isolate-0',
    swiftInferConfig: SwiftInferConfig(
      baseUrl: Uri.parse(endpoint),
      model: r['model'] as String,
      bearerToken: token,
    ),
    goal: r['goal'] as String,
    tools: <ToolDescriptor>[
      for (final String t in toolNames)
        ToolDescriptor(name: t, description: 'dogfood-injected $t',
            inputSchema: const <String, dynamic>{'type': 'object'}),
    ],
    fixture: fixture,
    maxTurns: int.parse(r['max-turns'] as String),
    maxTurnBudgetMs: int.parse(r['max-turn-budget-ms'] as String),
    traceSink: sink,
    tracePath: tracePath,
    verbose: r['verbose'] as bool,
    log: stdout.writeln,
  );
  final DogfoodRunResult result = await harness.run();
  stdout.writeln('dogfood: outcome=${result.outcome.name} '
      'tools=${result.toolCallCount} trace=$tracePath');
  return switch (result.outcome) {
    DogfoodOutcome.completedWithToolCall => 0,
    DogfoodOutcome.completedNoToolCall   => 0,
    DogfoodOutcome.typedException        => () {
        stderr.writeln('${result.exception.runtimeType}: ${result.exception}');
        return 1;
      }(),
    DogfoodOutcome.budgetExceeded        => 2,
  };
}

class _StandInPlugin extends ExplorationPlugin {
  _StandInPlugin(this._ns, this._all);
  final String _ns;
  final List<String> _all;
  @override String get namespace => _ns;
  @override List<ExplorationTool> get tools => <ExplorationTool>[
    for (final String t in _all)
      if (t.startsWith('$_ns.')) _NoopTool(t.substring(_ns.length + 1)),
  ];
  @override Future<void> initialize(PluginContext ctx) async {}
  @override Future<Map<String, Object?>?> observe(ObservationContext ctx)
      async => null;
  @override Future<BusyState> busyState() async => BusyState.idle;
  @override Future<void> onActionExecuted(ExecutedAction action) async {}
  @override Future<void> dispose() async {}
}

class _NoopTool extends ExplorationTool {
  _NoopTool(this._name);
  final String _name;
  @override String get name => _name;
  @override String get description => 'dogfood stand-in';
  @override JsonSchema get inputSchema =>
      const JsonSchema(<String, Object?>{'type': 'object'});
  @override Future<ToolResult> call(Map<String, Object?> args) async =>
      ToolResult(ok: true, value: args);
}
```

