```dart
/// Invoke a plugin tool extension by its fully-qualified service-extension
/// method name (e.g. `ext.flutter.exploration.sample.echo`). Resolves
/// the tool via [pluginRegistry]'s `mergedTools()` map (keyed by the
/// qualified `<ns>.<tool>` form) and wraps the result in the same
/// `{ok, value, error}` envelope `CorePlugin.initialize` uses, via
/// [dispatchToolToEnvelope].
///
/// Test-only: production callers reach plugin tools through the real
/// `developer.registerExtension` path. This bypass exists so
/// `flutter_test` integration tests can drive plugin tools without a
/// VM service connection.
@visibleForTesting
Future<String> invokePluginTool(
  String method,
  Map<String, String> params,
) async {
  const String prefix = '$kExplorationExtensionPrefix.';
  if (!method.startsWith(prefix)) {
    throw ArgumentError.value(method, 'method', 'must start with \"\$prefix\"');
  }
  final String tail = method.substring(prefix.length);
  final int dot = tail.indexOf('.');
  if (dot <= 0 || dot == tail.length - 1) {
    throw ArgumentError.value(method, 'method', 'malformed <ns>.<tool>');
  }
  final String qualified = tail; // already <ns>.<tool>
  final Map<String, ExplorationTool> merged = _pluginRegistry.mergedTools();
  final ExplorationTool? tool = merged[qualified];
  if (tool == null) {
    throw ArgumentError.value(
      method,
      'method',
      'no tool registered for \$qualified',
    );
  }
  final Map<String, Object?> args = decodeServiceExtensionParams(params);
  return dispatchToolToEnvelope(tool, args);
}
```

