  @override final String namespace;
  @override List<ExplorationTool> get tools => const [];
  @override Future<void> initialize(PluginContext c) async {}
  @override Future<Map<String, Object?>?> observe(ObservationContext c) async => null;
  @override Future<BusyState> busyState() async => BusyState.idle;
  @override Future<void> onActionExecuted(ExecutedAction a) async {}
  @override Future<void> dispose() async {}
}
class _RecApp implements ExplorationApp {
  ExplorationAppContext? seen;
  @override ExplorationAppConfig build(ExplorationAppContext ctx) {
    seen = ctx;
    return ExplorationAppConfig(
      plugins: [_Stub('app_${identityHashCode(this)}')],
      app: const SizedBox.shrink());
  }
