3. §2 hello-world plugin — `docs/plugin_authoring_guide.md`

   Single contiguous, copy-pasteable plugin importing only `package:exploration_flutter/contract.dart` and `package:flutter/foundation.dart`. Includes namespace, one tool, an `observe()` fragment surfacing one identifier (`session_id`), `busyState()` returning `BusyState.idle`, `initialize()` registering one chained error handler, `dispose()`. Use this exact code:

   ```dart
   import 'package:exploration_flutter/contract.dart';
   import 'package:flutter/foundation.dart';

   class HelloPlugin implements ExplorationPlugin {
     @override final String namespace = 'hello';
     @override final List<ExplorationTool> tools = [_GreetTool()];
     int _calls = 0;
     final String _sessionId = DateTime.now().microsecondsSinceEpoch.toRadixString(36);

     @override
     Future<void> initialize(PluginContext c) async {
       c.registerErrorHandler((d) { debugPrint('[hello] $d'); return false; });
     }
     @override
     Future<Map<String, Object?>?> observe(ObservationContext c) async => {
       'session_id': _sessionId, // surfaced because tools accept it (§21 convention)
       'calls_so_far': _calls,
     };
     @override
     Future<BusyState> busyState() async => BusyState.idle;
     @override
     Future<void> onActionExecuted(ExecutedAction a) async {
       if (a.toolName == 'hello.greet' && a.result.ok) _calls++;
     }
     @override
     Future<void> dispose() async {}
   }

   class _GreetTool implements ExplorationTool {
     @override final String name = 'greet';
     @override final String description = 'Returns a greeting for the given name.';
     @override final JsonSchema inputSchema = const JsonSchema({
       'type': 'object',
       'properties': {'name': {'type': 'string'}, 'session_id': {'type': 'string'}},
       'required': ['name'],
     });
     @override
     Future<ToolResult> call(Map<String, Object?> args) async {
       final n = args['name'];
       if (n is! String || n.isEmpty) return const ToolResult(ok: false, error: 'name required');
       return ToolResult(ok: true, value: 'hello, $n');
     }
   }
   ```

