   ```dart
   import 'package:flutter_riverpod/flutter_riverpod.dart';

   /// `debugLabel` when present, else the provider's runtimeType.
   String providerIdOf(ProviderBase<Object?> p) {
     final l = p.debugLabel;
     return (l != null && l.isNotEmpty) ? l : p.runtimeType.toString();
   }

   class StateChange {
     const StateChange({required this.providerId, required this.atTurn});
     final String providerId;
     final int atTurn;
     Map<String, Object?> toJson() =>
         {'provider_id': providerId, 'at_turn': atTurn};
   }

   class _Ring<T> {
     _Ring(this.cap);
     final int cap;
     final List<T> _xs = [];
     void add(T x) { _xs.add(x); if (_xs.length > cap) _xs.removeAt(0); }
     List<T> snapshot() => List.unmodifiable(_xs);
     void clear() => _xs.clear();
   }

   class ExplorationProviderObserver extends ProviderObserver {
     ExplorationProviderObserver({int ringCapacity = 16})
         : _changes = _Ring<StateChange>(ringCapacity);

     final Map<String, ProviderBase<Object?>> _live = {};
     final _Ring<StateChange> _changes;
     int currentTurn = 0;

     Map<String, ProviderBase<Object?>> get live => Map.unmodifiable(_live);
     List<StateChange> recentChanges() => _changes.snapshot();
     void clear() { _live.clear(); _changes.clear(); }

     @override
     void didAddProvider(ProviderObserverContext c, Object? v) {
       _live[providerIdOf(c.provider)] = c.provider;
     }
     @override
     void didDisposeProvider(ProviderObserverContext c) {
       _live.remove(providerIdOf(c.provider));
     }
     @override
     void didUpdateProvider(ProviderObserverContext c, Object? p, Object? n) {
       _changes.add(StateChange(
           providerId: providerIdOf(c.provider), atTurn: currentTurn));
     }
   }
   ```

