   Header/Turn/Footer/PluginDisabled `fromJson` factories already ship with .19's writer; this adds the union and parser.

   ```dart
   sealed class TrajectoryRecord {
     factory TrajectoryRecord.fromJson(Map<String, dynamic> j) =>
       switch (j['type']) {
         'header' => SessionHeader.fromJson(j),
         'turn' => TurnRecord.fromJson(j),
         'plugin_disabled' => PluginDisabledRecord.fromJson(j),
         'footer' => SessionFooter.fromJson(j),
         _ => UnknownRecord(rawType: j['type']?.toString() ?? 'null', raw: j),
       };
   }
   class UnknownRecord implements TrajectoryRecord {
     final String rawType; final Map<String, dynamic> raw;
     const UnknownRecord({required this.rawType, required this.raw});
   }
   class TrajectoryReader {
     static List<TrajectoryRecord> readAll(String jsonl) => [
       for (final l in const LineSplitter().convert(jsonl)) if (l.isNotEmpty)
         TrajectoryRecord.fromJson(jsonDecode(l) as Map<String, dynamic>)];
     static Stream<TrajectoryRecord> readStream(Stream<String> lines) =>
       lines.where((l) => l.isNotEmpty).map(
         (l) => TrajectoryRecord.fromJson(jsonDecode(l) as Map<String, dynamic>));
   }
   ```

