     static String _diff(ObservationDiff d) {
       final p = <String>[];
       if (d.core.nodesAdded.isNotEmpty) p.add('+${d.core.nodesAdded.length} nodes');
       if (d.core.nodesRemoved.isNotEmpty) p.add('-${d.core.nodesRemoved.length} nodes');
