5. `PromptPanelController` — `packages/exploration_devtools/lib/src/panels/prompt_panel_controller.dart`

   ```dart
   import 'dart:async';
   import 'package:exploration_agent/exploration_agent.dart';
   import 'prompt_panel_config.dart';
   typedef SessionFactory = ExplorationSession Function(Uri vmServiceUri);
   class PromptPanelController {
     final Uri vmServiceUri;
     final SessionFactory _factory;
     ExplorationSession? _session;
     final _events = StreamController<SessionProgressEvent>.broadcast();
     StreamSubscription<SessionProgressEvent>? _sub;
     PromptPanelController({required this.vmServiceUri, SessionFactory? factory})
       : _factory = factory ?? ((u) => ExplorationSession()..connect(u));
     bool get running => _session != null;
     Stream<SessionProgressEvent> get events => _events.stream;
     Future<void> start(PromptPanelConfig cfg) async {
       if (_session != null) throw StateError('session already running');
       final s = _factory(vmServiceUri); _session = s;
       _sub = s.progress.listen(_events.add);
       await s.start(cfg.goal, cfg.toExplorationConfig());
     }
     Future<void> stop() async {
       final s = _session; if (s == null) return;
       await s.end(); await _sub?.cancel();
       _sub = null; _session = null;
     }
     Future<void> dispose() async { await stop(); await _events.close(); }
   }
   ```

