4. FileTrajectorySink — `packages/exploration_cli/lib/src/file_trajectory_sink.dart`

   Implements .19's `TrajectorySink` (`writeLine(String)`, `close()`):
   ```dart
   import 'dart:convert';
   import 'dart:io';
   import 'package:exploration_agent/exploration_agent.dart' show TrajectorySink;
   import 'package:path/path.dart' as p;

   class FileTrajectorySink implements TrajectorySink {
     final IOSink _sink; final String path;
     FileTrajectorySink._(this._sink, this.path);

     static Future<FileTrajectorySink> open(String path) async {
       final f = File(path);
       await f.parent.create(recursive: true);
       return FileTrajectorySink._(
         f.openWrite(mode: FileMode.append, encoding: utf8), path);
     }
     @override
     Future<void> writeLine(String jsonLine) async {
       _sink.writeln(jsonLine);
       await _sink.flush(); // per-turn flush per .19
     }
     @override
     Future<void> close() async { await _sink.flush(); await _sink.close(); }

     static String defaultOutputPath({DateTime? now}) {
       final t = now ?? DateTime.now().toUtc();
       String two(int n) => n.toString().padLeft(2, '0');
       final s = '${t.year}${two(t.month)}${two(t.day)}T'
                 '${two(t.hour)}${two(t.minute)}${two(t.second)}Z';
       return p.join('trajectories', '$s.jsonl');
     }
   }
   ```

