   ```dart
   class ErrorEntry {
     ErrorEntry({required this.seq, required this.message,
                 required this.frames, required this.wallClockOffsetMs});
     final int seq;
     final String message;
     final List<String> frames; // <= 5
     final int wallClockOffsetMs;
     Map<String, Object?> toJson() => {
       'seq': seq, 'message': message,
       'frames': frames, 'wallClockOffsetMs': wallClockOffsetMs,
     };
   }
   class _ErrorRingBuffer {
     _ErrorRingBuffer({required this.capacity}) : assert(capacity > 0);
     final int capacity;
     final List<ErrorEntry> _ring = <ErrorEntry>[];
     int _nextSeq = 1;
     int get highestSeq => _nextSeq - 1;
     void add(String message, StackTrace? stack) {
       final frames = (stack?.toString() ?? '')
           .split('\n').where((s) => s.isNotEmpty).take(5).toList();
       _ring.add(ErrorEntry(
         seq: _nextSeq++, message: message, frames: frames,
         wallClockOffsetMs: _wallClockOffsetMs(),
       ));
       if (_ring.length > capacity) _ring.removeAt(0);
     }
     List<ErrorEntry> entriesSince(int sinceSeq) =>
         _ring.where((e) => e.seq > sinceSeq).toList(growable: false);
     int _wallClockOffsetMs() => /* set in step 1 from session start */;
   }
   ```

