3. Register the VM service extension on the binding — `exploration_flutter/lib/src/binding/exploration_binding.dart` (after the cx6.2 handshake registration)

   ```dart
   List<InteractiveSemanticsWarning>? _cachedDiagnostics;
   late final List<String> _extraInteractiveTypes;

   void _registerDiagnosticsExtension() {
     if (!kDebugMode && !kProfileMode) return;
     registerServiceExtension(
       name: 'exploration.core.diagnostics_warnings',
       callback: (_) async {
         try {
           _cachedDiagnostics ??= _runDiagnostic();
           return ServiceExtensionResponse.result(jsonEncode({
             'ok': true,
             'results': _cachedDiagnostics!.map((w) => w.toJson()).toList(),
           }));
         } catch (e, st) {
           debugPrint('exploration: diagnostics walk failed: $e\n$st');
           return ServiceExtensionResponse.result(jsonEncode({
             'ok': false, 'error': e.toString(), 'results': const [],
           }));
         }
       },
     );
   }

   List<InteractiveSemanticsWarning> _runDiagnostic() {
     final root = WidgetsBinding.instance.rootElement;
     if (root == null) return const [];
     return InteractiveSemanticsAuditor(
       extraInteractiveTypes: _extraInteractiveTypes,
     ).audit(root);
   }
   ```

